import operator
from abc import ABC, abstractmethod
from bisect import bisect
from itertools import permutations

import numpy as np

from ._interval import Interval, oo
from .geometry import (
    normalize,
    compute_angle,
    compute_angle_directions,
    project_line,
    compute_distance,
    farthest_from_value,
)


def check_interval(name, value, bounds, comparators):
    if not all(
        comparator(value, bound) for comparator, bound in zip(comparators, bounds)
    ):
        raise ValueError(
            "Invalid {} '{}'. Must be in interval {}".format(name, value, bounds)
        )


def check_distance(distance):
    check_interval("distance", distance, [0.0, np.inf], [operator.ge, operator.lt])


def check_angle(angle):
    check_interval("angle", angle, [0.0, np.pi / 2.0], [operator.ge, operator.lt])


def check_open_angle(angle):
    check_interval("angle", angle, [0.0, np.pi / 2.0], [operator.ge, operator.le])


def filter_arguments(arguments):
    return [] if any(argument is None for argument in arguments) else arguments


class SpaceError(Exception):
    pass


class SamePointError(SpaceError):
    pass


class InvalidLocalError(SpaceError):
    pass


class NotPositionedError(InvalidLocalError):
    pass


class NotOrientedError(InvalidLocalError):
    pass


class NotRadialError(InvalidLocalError):
    pass


class Spatial(ABC):
    @abstractmethod
    def local_pair(self, other) -> list:
        pass

    @abstractmethod
    def _is_valid(self, local) -> bool:
        pass

    def is_valid(self, local):
        return local is not None and self._is_valid(local)

    def check_validity(self, local):
        if not self.is_valid(local):
            raise InvalidLocalError(local)


class SpaceElement(ABC):
    @classmethod
    @abstractmethod
    def from_spatial(cls, spatial, local):
        pass

    @classmethod
    def from_spatial_location(cls, spatial_location):
        return cls.from_spatial(spatial_location.spatial, spatial_location.local)


class SpatialLocation:
    def __init__(self, spatial, local):
        self.spatial = spatial
        self.local = local

    def __repr__(self):
        return "{}({}, {})".format(
            self.__class__.__name__, str(self.spatial), str(self.local)
        )


class Positioned(Spatial):
    @property
    @abstractmethod
    def is_positioned(self) -> bool:
        pass

    def check_positioned(self):
        if not self.is_positioned:
            raise NotPositionedError(self)

    @abstractmethod
    def _to_point(self, local) -> np.ndarray:
        pass

    @abstractmethod
    def find_local_nearest_from_point(self, point):
        pass

    @abstractmethod
    def find_local_nearest(self, other):
        pass

    def local_pair(self, other):
        objects = [self, other]
        pair = [a.find_local_nearest(b) for a, b in permutations(objects, 2)]
        for positioned, local in zip(objects, pair):
            if not positioned.is_valid(local):
                raise InvalidLocalError(positioned, local)
        return pair

    def segment(self, other):
        return [
            positioned._to_point(local)
            for positioned, local in zip([self, other], self.local_pair(other))
        ]

    def distance(self, other):
        return compute_distance(*self.segment(other))

    def to_point(self, local):
        self.check_validity(local)
        return self._to_point(local)

    def vector(self, other):
        return np.diff(self.segment(other), axis=0)

    def axis_with(self, other):
        vector = self.vector(other)
        if not np.any(vector):
            raise SamePointError
        return normalize(vector)


class Oriented(Spatial):
    @property
    @abstractmethod
    def is_oriented(self) -> bool:
        pass

    def check_oriented(self):
        if not self.is_oriented:
            raise NotOrientedError(self)

    def axes(self, other):
        return [
            oriented._to_axis(local)
            for oriented, local in zip([self, other], self.local_pair(other))
        ]

    def angle_with(self, other):
        return compute_angle_directions(*self.axes(other))

    @abstractmethod
    def _to_axis(self, local) -> np.ndarray:
        pass

    def to_axis(self, local):
        self.check_validity(local)
        return self._to_axis(local)


class Circular(Spatial):
    @property
    @abstractmethod
    def is_radial(self) -> bool:
        pass

    def check_radial(self):
        if not self.is_radial:
            raise NotRadialError(self)

    @abstractmethod
    def _to_radius(self, local) -> float:
        pass

    def to_radius(self, local):
        self.check_validity(local)
        return self._to_radius(local)


class OrientedPositioned(Oriented, Positioned, ABC):
    def alignment_angle(self, other, angle):
        pair = self.local_pair(other)
        geometries = [self, other]
        point_a, point_b = [
            geometry._to_point(local) for geometry, local in zip(geometries, pair)
        ]
        if np.array_equal(point_a, point_b):
            raise SamePointError(point_a)
        axes = [geometry._to_axis(local) for geometry, local in zip(geometries, pair)]
        vector = normalize(point_b - point_a)
        return farthest_from_value(
            [compute_angle_directions(axis, vector) for axis in axes], angle
        )

    def longitudinality(self, other):
        return self.alignment_angle(other, 0.0)

    def transversality(self, other):
        return self.alignment_angle(other, np.pi / 2.0)


class Direction(Oriented, SpaceElement):
    def __init__(self, axis):
        self.axis = normalize(axis)

    @property
    def is_oriented(self):
        return True

    @classmethod
    def from_spatial(cls, spatial, local):
        return cls(spatial.to_axis(local))

    def local_pair(self, other):
        return [True, True]

    def _is_valid(self, local):
        return local is True

    def _to_axis(self, local):
        return self.axis

    def __repr__(self):
        return "{}({})".format(self.__class__.__name__, repr(self.axis))


class Space(Positioned):
    def _is_valid(self, local):
        return local in self

    def _to_point(self, local):
        return local

    @abstractmethod
    def __contains__(self, point):
        pass

    @abstractmethod
    def project_point_on_contour(self, point):
        pass

    def find_local_nearest_from_point(self, point):
        return point if point in self else self.project_point_on_contour(point)

    def intersect(self, other):
        return any(
            point in geometry
            for point, geometry in zip(self.local_pair(other), [other, self])
        )

    @abstractmethod
    def volume(self):
        pass


class Domain:
    def __init__(self, intervals):
        self.intervals = intervals.closure
        self.boundary = [] if intervals.is_empty else sorted(intervals.boundary)

    def nearest_bound(self, local):
        index = bisect(self.boundary, local)
        bounds = self.boundary[index - 1 : index + 1]
        return min(bounds, key=lambda x: abs(x - local), default=None)

    def __contains__(self, local):
        return local in self.intervals

    def nearest_insider(self, local):
        return local if local in self else self.nearest_bound(local)

    def __repr__(self):
        return "{}({})".format(self.__class__.__name__, repr(self.intervals))


class Parametric(Domain, Spatial, ABC):
    def _is_valid(self, local):
        return local in self


class Line(Parametric, OrientedPositioned):
    def __init__(self, origin, axis, intervals=Interval(-oo, oo)):
        Domain.__init__(self, intervals)
        self.axis = normalize(axis)
        self.origin = np.array(origin, float)

    @property
    def is_positioned(self):
        return True

    @property
    def is_oriented(self):
        return True

    def _to_axis(self, local):
        return self.axis

    def _to_point(self, local):
        return np.add(np.multiply(self.axis, local), self.origin)

    def find_local_nearest_from_point(self, point):
        return np.dot(np.subtract(point, self.origin), self.axis)

    def find_local_nearest(self, other):
        local = project_line(
            self.axis, other.axis, np.subtract(other.origin, self.origin)
        )
        return (
            self.nearest_insider(self.find_local_nearest_from_point(self.origin))
            if local is None
            else local
        )

    def __repr__(self):
        return "{}({}, {}, {})".format(
            self.__class__.__name__,
            repr(self.origin),
            repr(self.axis),
            repr(self.intervals),
        )


class Ray(Line):
    def __init__(self, origin, axis):
        Line.__init__(self, origin, axis, Interval(0.0, oo))


class Cone(Line, Circular):
    def __init__(self, origin, axis, angle, intervals=Interval(0.0, oo)):
        Line.__init__(self, origin, axis, intervals)
        self.angle = angle

    @property
    def is_radial(self):
        return True

    def _to_radius(self, local):
        return np.abs(local * np.tan(self.angle))

    def __repr__(self):
        return "{}({}, {}, {}, {})".format(
            self.__class__.__name__,
            repr(self.origin),
            repr(self.axis),
            repr(self.angle),
            repr(self.intervals),
        )

    @staticmethod
    def cone_from_limit(origin, axis, limit, intervals=Interval(0.0, oo)):
        return Cone(
            origin=origin,
            axis=axis,
            angle=compute_angle(axis, limit),
            intervals=intervals,
        )


class Cylinder(Line, Circular):
    def __init__(self, origin, axis, radius, intervals=Interval(-oo, oo)):
        super().__init__(origin, axis, intervals)
        self.radius = radius

    @property
    def is_radial(self):
        return True

    def _to_radius(self, local):
        return self.radius

    def __repr__(self):
        return "{}({}, {}, {}, {})".format(
            self.__class__.__name__,
            repr(self.origin),
            repr(self.axis),
            repr(self.radius),
            repr(self.intervals),
        )
